BoxDecoration myBoxDecoration = BoxDecoration(
  color: Colors.red,
  borderRadius: BorderRadius.circular(20.0),
  boxShadow: [
    BoxShadow(
      color: Colors.black54,
      offset: Offset(2.0, 2.0),
      blurRadius: 10.0,
